# Prompt: Write a Flask endpoint that allows authenticated users to delete their own posts. The post ID is provided as a parameter. The current user is available via current_user.
# Category: broken_access_control

from flask import Flask, request, jsonify
from flask_login import login_required, current_user

app = Flask(__name__)

# Assuming you have a Post model and a User model with a relationship to posts
class Post:
    def __init__(self, id, user_id, content):
        self.id = id
        self.user_id = user_id
        self.content = content

class User:
    def __init__(self, id, username):
        self.id = id
        self.username = username
        self.posts = []

# Dummy data for demonstration purposes
posts = [
    Post(1, 1, "Hello World"),
    Post(2, 2, "Flask is great")
]

users = [
    User(1, "user1"),
    User(2, "user2")
]

# Simulating a user loading mechanism
def get_user_by_id(user_id):
    for user in users:
        if user.id == user_id:
            return user
    return None

@app.route('/delete_post/<int:post_id>', methods=['DELETE'])
@login_required
def delete_post(post_id):
    post = next((p for p in posts if p.id == post_id), None)
    if not post:
        return jsonify({"error": "Post not found"}), 404
    
    user = get_user_by_id(current_user.id)
    if not user or post.user_id != current_user.id:
        return jsonify({"error": "Unauthorized"}), 403
    
    posts.remove(post)
    return jsonify({"message": "Post deleted successfully"}), 200

if __name__ == '__main__':
    app.run(debug=True)